```class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        unordered_set<int> res;
        for (int i = 0; pow(x, i) <= bound; ++i) {
            for (int j = 0; pow(x, i) + pow(y, j) <= bound; ++j) {
                res.insert(pow(x, i) + pow(y, j));
            }
        }
        return vector<int>(res.begin(), res.end());
    }
};
